nt":"Negative form of \\\"She is\\\" (variation)"},{"prompt":"Is it cold today?","options":["❄️","🍎","🏠","🚗"],"correct":0,"hint":"Question for weather (variation)"},{"prompt":"We are not here.","options":["📍","🍎","🏠","🚗"],"correct":0,"hint":"Negative of plural (variation)"},{"prompt":"Am You late?","options":["⌚","🍎","🏠","🚗"],"correct":0,"hint":"Question for self (variation)"},{"prompt":"She are not happy.","options":["😢","🍎","🏠","🚗"],"correct":0,"hint":"Negative adjective (variation)"},{"prompt":"Are we friends?","options":["🤝","🍎","🏠","🚗"],"correct":0,"hint":"Question for us (variation)"},{"prompt":"You are not old.","options":["👶","🍎","🏠","🚗"],"correct":0,"hint":"Negative adjective (variation)"},{"prompt":"Is the water hot?","options":["🔥","🍎","🏠","🚗"],"correct":0,"hint":"Question for thing (variation)"}]}', 1);
