('en_a1', 'A1', 'writing', 'To be (Questions & Negatives)', 'Learn how to ask questions and say "no" with the verb to be.', '{"tutorial":[{"visual":"👨‍⚕️","title":"To be (Questions & Negatives)","text":"I am not a doctor."},{"visual":"🍕","title":"To be (Questions & Negatives)","text":"Are you hungry?"},{"visual":"🇬🇧","title":"To be (Questions & Negatives)","text":"She is not English."},{"visual":"❄️","title":"To be (Questions & Negatives)","text":"Is it cold today?"},{"visual":"📍","title":"To be (Questions & Negatives)","text":"They are not here."}],"type":"type_word","instructions":"Type the missing grammar part.","exercises":[{"prompt":"👨‍⚕️ ... am not a doctor.","expected":"i","hint":"The word starts with \\\"I\\\""},{"prompt":"🍕 ... you hungry?","expected":"are","hint":"The word starts with \\\"A\\\""},{"prompt":"🇬🇧 ... is not English.","expected":"she","hint":"The word starts with \\\"S\\\""},{"prompt":"❄️ ... it cold today?","expected":"is","hint":"The word starts with \\\"I\\\""},{"prompt":"📍 ... are not here.","expected":"they","hint":"The word starts with \\\"T\\\""},{"prompt":"⌚ ... I late?","expected":"am","hint":"The word starts with \\\"A\\\""},{"prompt":"😢 ... is not happy.","expected":"he","hint":"The word starts with \\\"H\\\""},{"prompt":"🤝 ... we friends?","expected":"are","hint":"The word starts with \\\"A\\\""},{"prompt":"👶 ... are not old.","expected":"you","hint":"The word starts with \\\"Y\\\""},{"prompt":"🔥 ... the water hot?","expected":"is","hint":"The word starts with \\\"I\\\""},{"prompt":"👨‍⚕️ ... are not a doctor.","expected":"you","hint":"The word starts with \\\"Y\\\""},{"prompt":"🍕 ... you hungry?","expected":"are","hint":"The word starts with \\\"A\\\""},{"prompt":"🇬🇧 ... are not English.","expected":"she","hint":"The word starts with \\\"S\\\""},{"prompt":"❄️ ... it cold today?","expected":"is","hint":"The word starts with \\\"I\\\""},{"prompt":"📍 ... are not here.","expected":"we","hint":"The word starts with \\\"W\\\""},{"prompt"