('en_a1', 'A1', 'listening', 'Present Simple (Habits & Routines)', 'Talk about things you do every day.', '{"tutorial":[{"visual":"☕","title":"Present Simple (Habits & Routines)","text":"I drink coffee every morning."},{"visual":"💼","title":"Present Simple (Habits & Routines)","text":"She goes to work at 8 AM."},{"visual":"⚽","title":"Present Simple (Habits & Routines)","text":"They play football on Sundays."},{"visual":"🏦","title":"Present Simple (Habits & Routines)","text":"He works in a bank."},{"visual":"🌆","title":"Present Simple (Habits & Routines)","text":"We live in London."}],"type":"listen_and_choose","instructions":"Listen and pick the correct card.","exercises":[{"prompt":"I drink coffee every morning.","options":["☕","🍎","🏠","🚗"],"correct":0,"hint":"Morning habit"},{"prompt":"She goes to work at 8 AM.","options":["💼","🍎","🏠","🚗"],"correct":0,"hint":"Daily routine"},{"prompt":"They play football on Sundays.","options":["⚽","🍎","🏠","🚗"],"correct":0,"hint":"Weekly activity"},{"prompt":"He works in a bank.","options":["🏦","🍎","🏠","🚗"],"correct":0,"hint":"Job description"},{"prompt":"We live in London.","options":["🌆","🍎","🏠","🚗"],"correct":0,"hint":"Permanent state"},{"prompt":"I never eat fish.","options":["🐟","🍎","🏠","🚗"],"correct":0,"hint":"Negative habit"},{"prompt":"Does he like tea?","options":["🍵","🍎","🏠","🚗"],"correct":0,"hint":"Question for habits"},{"prompt":"The sun rises in the east.","options":["🌅","🍎","🏠","🚗"],"correct":0,"hint":"General truth"},{"prompt":"My sister speaks Spanish.","options":["🇪🇸","🍎","🏠","🚗"],"correct":0,"hint":"Third person -s"},{"prompt":"Cats love milk.","options":["🐱","🍎","🏠","🚗"],"correct":0,"hint":"General fact"},{"prompt":"You drink coffee every morning.","options":["☕","🍎","🏠","🚗"],"correct":0,"hint":"Morning habit (variation)"},{"prompt":"She goes to work at 8 AM.","options":["💼","🍎","🏠","🚗"],"correct":0,"hint":"Daily routine (variation)"},{"prompt":"We play football on Sundays.","options":["⚽","🍎","🏠","🚗"],"correct":0,"hint":"Weekly activity (variation)"},{"prompt":"She works in a bank.","options":["🏦","🍎","🏠","🚗"],"correct":0,"hint":"Job description (variation)"},{"prompt":"We live in London.","options":["🌆","🍎","🏠","🚗"],"correct":0,"hint":"Permanent state (variation)"},{"prompt":"You never eat fish.","options":["🐟","🍎","🏠","🚗"],"correct":0,"hint":"Negative habit (variation)"},{"prompt":"Does he like tea?","options":["🍵","🍎","🏠","🚗"],"correct":0,"hint":"Question for habits (variation)"},{"prompt":"The sun rises in the east.","options":["🌅","🍎","🏠","🚗"],"correct":0,"hint":"General truth (variation)"},{"prompt":"My sister speaks Spanish.","options":["🇪🇸","🍎","🏠","🚗"],"correct":0,"hint":"Third person -s (variation)"},{"prompt":"Cats love milk.","options":["🐱","🍎","🏠","🚗"],"correct":0,"hint":"General fact (variation)"}]}', 2);
