e","hint":"The word starts with \\\"S\\\""},{"prompt":"🐦 ... can fly.","expected":"birds","hint":"The word starts with \\\"B\\\""},{"prompt":"🔑 ... can''t find the keys.","expected":"we","hint":"The word starts with \\\"W\\\""},{"prompt":"🍝 ... she cook Italian food?","expected":"can","hint":"The word starts with \\\"C\\\""},{"prompt":"🤝 ... can help you.","expected":"you","hint":"The word starts with \\\"Y\\\""},{"prompt":"🐟 ... can''t walk.","expected":"fish","hint":"The word starts with \\\"F\\\""}]}', 10);
