"🚗"],"correct":0,"hint":"Asking for person (variation)"},{"prompt":"Why are you crying?","options":["😢","🍎","🏠","🚗"],"correct":0,"hint":"Asking for reason (variation)"},{"prompt":"How are you?","options":["😊","🍎","🏠","🚗"],"correct":0,"hint":"Asking for state (variation)"},{"prompt":"Whose bag are this?","options":["👜","🍎","🏠","🚗"],"correct":0,"hint":"Asking for owner (variation)"},{"prompt":"Which color do you like?","options":["🎨","🍎","🏠","🚗"],"correct":0,"hint":"Choosing from options (variation)"},{"prompt":"How much does it cost?","options":["💰","🍎","🏠","🚗"],"correct":0,"hint":"Asking for price (variation)"},{"prompt":"How many sisters do you have?","options":["👭","🍎","🏠","🚗"],"correct":0,"hint":"Asking for quantity (variation)"}]}', 12);
